// ═══════════════════════════════════════════════════════════════
// NORMALIZE & DEDUP — Config-based adapter for any job board
// To add a new board: add an entry to BOARD_CONFIG, wire the
// Apify node to this Code node, done. Nothing else changes.
// ═══════════════════════════════════════════════════════════════

const BOARD_CONFIG = {
  'Run an Actor and get dataset': {
    source: 'LinkedIn',
    fields: {
      id:          'id',
      title:       ['title', 'jobTitle'],
      company:     ['companyName', 'company'],
      location:    'location',
      description: ['descriptionText', 'description'],
      url:         ['link', 'url'],
      applyUrl:    ['applyUrl', 'link'],
      postedAt:    'postedAt',
      salary:      'salary',
      remote:      'workRemoteAllowed',
      seniority:   ['seniorityLevel', 'seniority'],
      country:     'country',
    }
  },
  'Run an Actor and get dataset1': {
    source: 'Indeed',
    fields: {
      id:          'key',
      title:       'title',
      company:     'employer.name',
      location:    'location.city',
      description: 'description.text',
      url:         ['url', 'jobUrl'],
      applyUrl:    ['url', 'jobUrl'],
      postedAt:    'datePublished',
      salary:      null,
      remote:      null,
      seniority:   null,
      country:     'location.countryCode',
    }
  },
  'Run an Actor and get dataset2': {
    source: 'StepStone',
    fields: {
      id:          'id',
      title:       'title',
      company:     'company_details.company_name',
      location:    'workplace_details.job_location',
      description: 'content_details.full_description',
      url:         'source.url',
      applyUrl:    'detail_page.applying_details.applying_url',
      postedAt:    'posting_details.published_at',
      salary:      'compensation_details.detail_salary',
      remote:      'workplace_details.work_arrangement',
      seniority:   null,
      country:     null,  // StepStone.de is DACH-only — skip code filter
    }
  },
  'Run an Actor and get dataset3': {
    source: 'Glassdoor',
    fields: {
      id:          'key',
      title:       'title',
      company:     'company.companyName',
      location:    'location_city',
      description: 'description_text',
      url:         'jobUrl',
      applyUrl:    'applyUrl',
      postedAt:    'datePublished',
      salary:      null,  // flat baseSalary_min/max handled in extractSalary
      remote:      'remoteWorkTypes',
      seniority:   null,
      country:     null,  // location_country is "Germany" not a code; Glassdoor.de is DACH-only
    }
  },
  'Run an Actor and get dataset4': {
    source: 'Xing',
    fields: {
      id:          'job_id',
      title:       'title',
      company:     'company',
      location:    'location',
      description: 'description_text',
      url:         'url',
      applyUrl:    'apply_url',
      postedAt:    'date_posted',
      salary:      'salary',
      remote:      'remote',
      seniority:   null,
      country:     'location_country_code',
    }
  },
};

const ALLOWED_COUNTRIES = new Set(['DE', 'AT', 'CH', 'NL', 'BE', '']);

function getNestedValue(obj, path) {
  if (!path) return undefined;
  return path.split('.').reduce((o, k) => (o && o[k] !== undefined) ? o[k] : undefined, obj);
}

function resolveField(obj, mapping) {
  if (mapping === null || mapping === undefined) return '';
  if (Array.isArray(mapping)) {
    for (const path of mapping) {
      const val = getNestedValue(obj, path);
      if (val !== undefined && val !== null && val !== '') return val;
    }
    return '';
  }
  return getNestedValue(obj, mapping) || '';
}

function extractSalary(obj, config) {
  const raw = resolveField(obj, config.fields.salary);
  // Already a string (Xing, LinkedIn)
  if (raw && typeof raw === 'string' && raw.length > 0) return raw;
  // StepStone: { min, max, currency, period }
  if (raw && typeof raw === 'object' && raw.min) {
    const { min, max, currency, currencyIso, period } = raw;
    return `${currency || currencyIso || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  // LinkedIn: baseSalary nested object
  if (obj.baseSalary && obj.baseSalary.min) {
    const { min, max, currencyCode, unitOfWork } = obj.baseSalary;
    return `${currencyCode || ''} ${min}-${max}/${unitOfWork || ''}`.trim();
  }
  // Glassdoor: flat baseSalary_min / baseSalary_max fields
  if (obj.baseSalary_min) {
    const { baseSalary_min: min, baseSalary_max: max, salary_currency: cur, salary_period: period } = obj;
    return `${cur || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  return '';
}

const jobs = [];

for (const [nodeName, config] of Object.entries(BOARD_CONFIG)) {
  let items;
  try {
    items = $(nodeName).all();
  } catch (e) {
    continue;
  }
  if (!items || items.length === 0) continue;

  for (const item of items) {
    const d = item.json;
    if (!d || typeof d !== 'object') continue;

    const desc = String(resolveField(d, config.fields.description));
    if (desc.length < 20) continue;

    const country = String(resolveField(d, config.fields.country) || '').toUpperCase();
    if (country && !ALLOWED_COUNTRIES.has(country)) continue;

    jobs.push({
      source:      config.source,
      id:          String(resolveField(d, config.fields.id)),
      title:       String(resolveField(d, config.fields.title)),
      company:     String(resolveField(d, config.fields.company)),
      location:    String(resolveField(d, config.fields.location)),
      description: desc,
      url:         String(resolveField(d, config.fields.url)),
      applyUrl:    String(resolveField(d, config.fields.applyUrl)),
      postedAt:    String(resolveField(d, config.fields.postedAt)),
      salary:      extractSalary(d, config),
      remote:      Boolean(resolveField(d, config.fields.remote)),
      seniority:   String(resolveField(d, config.fields.seniority)),
    });
  }
}

const seen = new Set();
const unique = [];
for (const job of jobs) {
  const key = job.applyUrl || `${job.company}::${job.title}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(job);
}

if (unique.length === 0) {
  return [{ json: { error: 'No valid jobs after normalize + dedup. Check Apify outputs and country filter.', rawCount: jobs.length } }];
}

return unique.map(j => ({ json: j }));

const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { _emptySheet: true } }];
}
return rows;

// Get all scraped jobs from normalize step
const jobs = $('3. Normalize & Merge Jobs').all();

// Build set of already-seen job URLs from Sheets
const seenUrls = new Set();
try {
  const sheetRows = $('6a. Read Applied Jobs').all();
  for (const row of sheetRows) {
    // Only suppress URLs for jobs that were actually processed (not skipped)
    // Skipped rows (Applied = 'N/A') should remain eligible for re-evaluation
    if ((row.json['Applied'] || '').trim() === 'N/A') continue;
    const url = (row.json['Job URL'] || '').trim();
    if (url) seenUrls.add(url);
  }
} catch (e) {
  // Sheet is empty on first run — that's fine
}

// Filter to only new jobs not yet in Sheets
const newJobs = jobs.filter(job => {
  const url = (job.json.url || job.json.applyUrl || '').trim();
  return url && !seenUrls.has(url);
});

if (newJobs.length === 0) {
  return [{ json: { skipped: true, message: 'No new jobs — all already logged in Sheets', totalScraped: jobs.length } }];
}

console.log(`New jobs to process: ${newJobs.length} / ${jobs.length} scraped`);
return newJobs;

const resumeItem = $('4. GET Resume Context').first();
// If the resume server is down, continueOnFail gives us an error item.
// Fall back to an empty resume object so the pipeline can still run and log jobs.
const resumeContext = (resumeItem.json && !resumeItem.json.error)
  ? resumeItem.json
  : {};

const jobs = $('6b. Filter Duplicates').all();

return jobs.map(job => ({
  json: {
    ...job.json,
    resume: resumeContext,
    _resumeFallback: Object.keys(resumeContext).length === 0
  }
}));

const item = $json;

// Skip non-job items safely
if (item.skipped || item.error) {
  return {
    json: {
      ...item,
      _skip: true,
    },
  };
}

// MUST include "JSON" for Groq response_format
const systemPrompt = `You are a job-match filter.

Return ONLY valid JSON. No explanation, no text outside JSON.

Output format:
{
  "match": true or false,
  "confidence": number (0-100),
  "reason": "one short line",
  "jobType": "internship|werkstudent|full-time|contract|unknown"
}

Rules:
- Be LENIENT (Germany job search context)
- match=true if ANY:
  - 40%+ skill overlap
  - internship/Werkstudent (almost always true)
  - junior/entry roles
  - transferable software/backend skills
- match=false ONLY if:
  - completely unrelated field (law, finance, medical, etc.)
  - pure ML/Data Science role (unless mixed with software dev)
  - strict senior role (6+ years AND narrow specialization)
`;

// ===== Helper =====
const clean = (s) => (s || '').replace(/\s+/g, ' ').trim();

// ===== Resume Data =====
const skills = (item.resume?.currentSkills || [])
  .map(s => s?.skill || '')
  .filter(Boolean)
  .join(', ');

const education = (item.resume?.education || [])
  .map(e =>
    `${e.degree || ''} ${e.field || ''} at ${e.institution || ''} (${e.year || ''})`.trim()
  )
  .join('; ');

const recentWork = (item.resume?.workExperience || [])
  .slice(0, 2)
  .map(w =>
    `${w.title || ''} at ${w.company || ''}: ${(w.summary || '').slice(0, 120)}`
  )
  .join(' | ');

// ===== Smart JD Extraction (EN + DE aware) =====
const jdRaw = item.description || '';
const jd = clean(jdRaw);

// Split by important sections (English + German)
const parts = jd.split(
  /requirements|qualifications|your profile|anforderungen|qualifikationen|profil|was Sie mitbringen|was du mitbringst/i
);

// Pick best section or fallback
let jdImportant =
  parts.length > 1 && parts[1].trim().length > 120
    ? parts[1]
    : jd;

// Add intro for context only if meaningful
const intro = jd.length > 400 ? jd.slice(0, 300) : '';

// Combine intro + requirements
jdImportant = intro
  ? `${intro}\n\n${jdImportant}`
  : jdImportant;

// Remove HTML tags if present
jdImportant = jdImportant.replace(/<[^>]+>/g, '');

// Final cap for token safety
jdImportant = jdImportant.slice(0, 1500);

// ===== Build User Prompt =====
const userMsg = `Candidate:
Title: ${item.resume?.currentJobTitle || 'Software Developer'}
Location: Germany

Education:
${education || 'MSc Global Software Development, Hochschule Fulda Germany'}

Recent Work:
${recentWork || 'N/A'}

Skills:
${skills || 'N/A'}

Job:
${item.title} at ${item.company}
Location: ${item.location}
Seniority: ${item.seniority || 'unspecified'}

Job Description:
${jdImportant}`;

// ===== Final Output =====
return {
  json: {
    ...item,
    _groqBody: {
      model: 'llama-3.1-8b-instant',
      temperature: 0.1,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg },
      ],
    },
  },
};

// 8. Parse Match Result

const aiResponse = $json;
const jobData = $('7a. Build Match Prompt').item.json;
const { _groqBody, ...cleanJobData } = jobData;

// Handle rate limit or API error from node 7b
if (aiResponse.error) {
  return {
    json: {
      ...cleanJobData,
      matchResult: {
        match: false,
        confidence: 0,
        reason: 'Groq API error: ' + (aiResponse.error.message || 'unknown'),
        jobType: 'unknown',
        _apiError: true,
      },
    },
  };
}

try {
  const content = aiResponse.choices[0].message.content;
  const result = JSON.parse(content);
  return {
    json: {
      ...cleanJobData,
      matchResult: result,
    },
  };
} catch (err) {
  return {
    json: {
      ...cleanJobData,
      matchResult: {
        match: true,
        confidence: 50,
        reason: 'AI parse error - defaulting to match: ' + err.message,
        jobType: 'unknown',
      },
    },
  };
}

// 10a. Build Tailor Prompt — production-grade version

const item = $json;
const staticData = $getWorkflowStaticData('global');

// ===== Rate limiting =====
const PRE_CALL_DELAY_MS = 6000;
const lastCall = staticData.lastOpenAICallAt || 0;
const elapsed = Date.now() - lastCall;
if (elapsed < PRE_CALL_DELAY_MS) {
  await new Promise(r => setTimeout(r, PRE_CALL_DELAY_MS - elapsed));
}
staticData.lastOpenAICallAt = Date.now();

// ===== Helpers =====
const clean = (s) => (s || '').replace(/\s+/g, ' ').trim();
const stripHtml = (s) => (s || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

// ===== Smart JD extraction =====
const jdRaw = item.description || '';
const jd = clean(jdRaw);

const parts = jd.split(
  /requirements|qualifications|your profile|anforderungen|qualifikationen|profil|was Sie mitbringen|was du mitbringst/i
);

let jdImportant =
  parts.length > 1 && parts[1].trim().length > 120
    ? parts[1]
    : jd;

const intro = jd.length > 400 ? jd.slice(0, 300) : '';

jdImportant = intro
  ? `${intro}\n\n${jdImportant}`
  : jdImportant;

jdImportant = jdImportant.replace(/<[^>]+>/g, '').slice(0, 1800).trim();

// ===== Strip HTML from resume input =====
// Prevents model from confusing input HTML with output format instructions
const workClean = (item.resume?.currentWork || []).map(w => ({
  ...w,
  description: stripHtml(w.description),
}));

const skillsClean = (item.resume?.currentSkills || []).map(s => ({
  ...s,
  infoHtml: stripHtml(s.infoHtml),
}));

// ===== System Prompt =====
const systemPrompt = `You are an expert resume and cover letter writer for tech jobs in Germany.

Your goal is NOT to write nicely — your goal is to maximize interview callback rate.

The output MUST be strictly valid JSON.
- No text before or after the JSON object
- No comments
- No trailing commas
- No additional keys beyond the schema

========================
RESUME PATCH RULES
========================

GENERAL:
- ONLY modify sections that improve relevance to this specific job
- DO NOT invent experience, skills, or tools not already in the resume
- Preserve original meaning — only optimize wording and relevance
- Make minimal edits for maximum impact
- Each sentence must add new information — no filler, no repetition
- Avoid generic statements that could apply to any company or role

PROFILE (3–4 sentences):
- Mention MSc Global Software Development (Hochschule Fulda, Germany)
- Align current title to the job role
- Highlight core tech stack matching the job description
- Clearly state target role

WORK EXPERIENCE:
- Incorporate keywords from the job description ONLY when natural
- Prefer exact wording for tools/technologies (ATS optimization)
- DO NOT force keywords if it harms readability
- Focus on technologies used and measurable impact
- Start bullets with action or outcome when possible
- Use action verbs: Built, Implemented, Optimized, Designed, Automated, Reduced, Delivered
- NEVER use: "worked on", "responsible for", "helped with", "assisted", "was involved in"

SKILLS:
- Prioritize and reorder skills based on job relevance
- Align wording with job description terminology

STRICT:
- Keep all entry IDs exactly as given — never modify or omit them
- Do not create new entries or sections
- Do not remove existing entries
- HTML formatting ONLY where required by schema

========================
COVER LETTER RULES (GERMANY STYLE)
========================

- EXACTLY 3 paragraphs
- 180–220 words total
- Plain text only

P1:
- State role and company name
- Mention MSc Hochschule Fulda (Germany)
- Start with a strong, specific hook tied to relevant experience

P2:
- 2–3 concrete skills or project outcomes aligned with the job
- Include specific technologies and results
- No generic claims

P3:
- Clearly state availability (internship / Werkstudent / full-time)
- Match jobType context
- End with a confident and direct closing

STRICT:
- No clichés: "passionate", "excited", "team player", "fast learner", "driven"
- No greetings, no date, no subject line, no sign-off
- No repetition of resume bullets
- Avoid generic statements
- Each sentence must add value
- If job requires German and resume does not show it → do NOT claim German skills

========================
OUTPUT FORMAT (STRICT JSON)
========================

{
  "patch": {
    "jobTitle": "string (omit key if unchanged)",
    "profile": "<p>...</p> (omit key if no improvement)",
    "work": [
      {
        "id": "existing-id",
        "description": "<ul><li><p>...</p></li></ul>"
      }
    ],
    "skills": [
      {
        "id": "existing-id",
        "infoHtml": "<p>...</p>"
      }
    ]
  },
  "coverLetter": "paragraph one\\n\\nparagraph two\\n\\nparagraph three"
}

========================
FINAL RULES
========================

- Always make at least one meaningful improvement if possible
- Only return an empty patch if absolutely no improvement can be made
- Ensure JSON is valid and parseable
- Do not include any text outside the JSON object`;

// ===== User Message =====
const userMsg = `RESUME:
Title: ${item.resume?.currentJobTitle || ''}
Profile: ${stripHtml(item.resume?.currentProfile || '')}
Work: ${JSON.stringify(workClean)}
Skills: ${JSON.stringify(skillsClean)}

JOB DETAILS:
Role: ${item.title}
Company: ${item.company}
Location: ${item.location}
Seniority: ${item.seniority || 'unspecified'}
Type: ${item.matchResult?.jobType || 'unknown'}

JOB DESCRIPTION:
${jdImportant}`;

// ===== Final Output =====
return {
  json: {
    ...item,
    _openAIBody: {
      model: 'gpt-4o-mini',
      temperature: 0.3,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg },
      ],
    },
  },
};

// Single combined AI call returns both patch and coverLetter

// Current item = OpenAI HTTP response for this job
const aiResponse = $json;

// Original job from 10a, matched by index
const jobData = $('10a. Build Tailor Prompt').item.json;

let patch = {};
let coverLetter = '';

try {
  if (!aiResponse?.choices?.[0]?.message?.content) {
    throw new Error('No choices in AI response — possible rate limit or API error');
  }
  const result = JSON.parse(aiResponse.choices[0].message.content);
  patch = result.patch || {};
  coverLetter = result.coverLetter || '';
} catch (err) {
  patch = { _error: 'AI parse failed: ' + err.message };
  coverLetter = '';
}

const rawParts = (coverLetter || '')
  .split(/\n\n+/)
  .map(p => p.trim())
  .filter(p => p.length > 0);

let paragraph1 = rawParts[0] || '';
let paragraph2 = rawParts[1] || '';
let paragraph3 = rawParts[2] || '';
let _coverLetterWarning = '';

if (rawParts.length === 0) {
  _coverLetterWarning = 'AI returned empty cover letter';
} else if (rawParts.length < 3) {
  _coverLetterWarning = `Cover letter has ${rawParts.length} paragraph(s), expected 3`;
  if (rawParts.length === 1 && rawParts[0].length > 100) {
    const sentences = rawParts[0].split(/(?<=[.!?])\s+/);
    if (sentences.length >= 3) {
      const third = Math.floor(sentences.length / 3);
      paragraph1 = sentences.slice(0, third).join(' ');
      paragraph2 = sentences.slice(third, third * 2).join(' ');
      paragraph3 = sentences.slice(third * 2).join(' ');
      _coverLetterWarning += ' — recovered via sentence split';
    }
  }
}

return {
  json: {
    patch,
    coverLetter,
    paragraph1,
    paragraph2,
    paragraph3,
    _coverLetterWarning,
    job: {
      source:          jobData.source || '',
      title:           jobData.title || '',
      company:         jobData.company || '',
      location:        jobData.location || '',
      url:             jobData.url || '',
      applyUrl:        jobData.applyUrl || '',
      postedAt:        jobData.postedAt || '',
      salary:          jobData.salary || '',
      jobType:         jobData.matchResult?.jobType || 'unknown',
      matchConfidence: jobData.matchResult?.confidence || 0,
      matchReason:     jobData.matchResult?.reason || '',
    },
  },
};

const patchData = $('11. Parse AI Patch').item.json;
const resumeResult = $('12. POST Generate Resume PDF').item.json;

// Current item = cover letter HTTP response
const coverLetterResult = $json;

const now = new Date();

return {
  json: {
    Date:               now.toISOString().slice(0, 19),
    Company:            patchData.job.company || '',
    Role:               patchData.job.title || '',
    'Job Type':         patchData.job.jobType || '',
    Location:           patchData.job.location || '',
    Source:             patchData.job.source || '',
    'Job URL':          patchData.job.url || '',
    'Apply URL':        patchData.job.applyUrl || '',
    'Match Confidence': patchData.job.matchConfidence || 0,
    'Match Reason':     patchData.job.matchReason || '',
    'Resume File':      resumeResult.file || '',
    'Cover Letter File': coverLetterResult.file || '',
    Status:             (resumeResult.success && coverLetterResult.success) ? 'Generated' : 'PDF Failed',
    Applied:            'No',
    Response:           '',
    Interview:          '',
    Notes:              patchData.patch?._error || patchData._coverLetterWarning || '',
  },
};

const jobData = $json;

const now = new Date();

return {
  json: {
    Date:               now.toISOString().slice(0, 19),
    Company:            jobData.company || '',
    Role:               jobData.title || '',
    'Job Type':         jobData.matchResult?.jobType || '',
    Location:           jobData.location || '',
    Source:             jobData.source || '',
    'Job URL':          jobData.url || '',
    'Apply URL':        jobData.applyUrl || '',
    'Match Confidence': jobData.matchResult?.confidence || 0,
    'Match Reason':     jobData.matchResult?.reason || '',
    'Resume File':      '',
    'Cover Letter File': '',
    Status:             'Skipped - No Match',
    Applied:            'N/A',
    Response:           '',
    Interview:          '',
    Notes:              ''
  }
};
